];

const item = $input.first();
const data = item.json;

// Parse the AI's JSON string
let classification;

try {
    classification = JSON.parse(data.output);
} catch (error) {
    throw new Error("❌ AI output is not valid JSON.");
}

// Ensure the category exists
if (!classification.category) {
    throw new Error("❌ Missing 'category' field.");
}

// Allowed categories
const allowedCategories = [
    "Work",
    "Personal",
    "Finance",
    "Promotions",
    "Spam"
];

// Validate the category
if (!allowedCategories.includes(classification.category)) {
    throw new Error(
        `❌ Invalid category: ${classification.category}`
    );
}

// Return everything for the next node
return [
    {
        json: {
            ...data,

            // Parsed AI output
            aiClassification: classification,

            // Regression test results
            testResults: {
                ...(data.testResults ?? {}),
                v002: {
                    passed: true,
                    category: classification.category,
                    timestamp: new Date().toISOString()
                }
            }
        }
    }
];

const item = $input.first();
const data = item.json;

let classification;

try {
    classification = JSON.parse(data.output);
} catch (error) {
    throw new Error("❌ AI output is not valid JSON.");
}

// Required field
if (!classification.hasOwnProperty("category")) {
    throw new Error("❌ Missing 'category' field.");
}

// Type check
if (typeof classification.category !== "string") {
    throw new Error("❌ 'category' must be a string.");
}

// Allowed values
const allowedCategories = [
    "Work",
    "Personal",
    "Finance",
    "Promotions",
    "Spam"
];

if (!allowedCategories.includes(classification.category)) {
    throw new Error(
        `❌ Invalid category: ${classification.category}`
    );
}

// Ensure no unexpected fields
const allowedFields = ["category"];
const extraFields = Object.keys(classification)
    .filter(key => !allowedFields.includes(key));

if (extraFields.length > 0) {
    throw new Error(
        `❌ Unexpected fields: ${extraFields.join(", ")}`
    );
}

return [{
    json: {
        ...data,
        aiClassification: classification,
        testResults: {
            ...(data.testResults ?? {}),
            v003: {
                passed: true,
                schemaValidated: true,
                timestamp: new Date().toISOString()
            }
        }
    }
}];
